export async function*streamAIResponse(e,n,t,o){const r=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{Authorization:`Bearer ${t}`,"Content-Type":"application/json","HTTP-Referer":"chrome-extension://personal-assistant","X-Title":"Personal Assistant"},body:JSON.stringify({model:o,stream:!0,max_tokens:400,temperature:.3,messages:[{role:"system",content:n},{role:"user",content:e}]})});if(!r.ok){if(401===r.status)throw new Error("Invalid API key");if(429===r.status)throw new Error("Rate limit exceeded");throw new Error(`API error: ${r.status}`)}const s=r.body.getReader(),a=new TextDecoder;for(;;){const{done:e,value:n}=await s.read();if(e)break;const t=a.decode(n).split("\n").filter(e=>e.startsWith("data: "));for(const e of t){const n=e.replace("data: ","");if("[DONE]"===n.trim())return;try{const e=JSON.parse(n),t=e.choices?.[0]?.delta?.content;t&&(yield t)}catch{}}}}export async function generateResponse(e,n,t){const o=`Meeting context: ${n}\n\nQuestion: ${e}\n\nProvide a helpful, concise answer:`,r=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{Authorization:`Bearer ${t}`,"Content-Type":"application/json"},body:JSON.stringify({model:"meta-llama/llama-3.1-8b-instruct:free",messages:[{role:"user",content:o}],max_tokens:300,temperature:.3})});return(await r.json()).choices[0].message.content}export function buildSystemPrompt(e){const n='You are an AI assistant embedded in a Chrome extension that helps a \nprofessional during live business calls and meetings.\n\nYour role:\n- Provide clear, accurate, concise answers to questions asked by the \n  other person in the meeting.\n- Responses must be 3–5 sentences maximum. The user is on a live call \n  and needs to respond in seconds.\n- Be direct and factual. Skip preambles like "Great question!" or \n  "Certainly!". Start your answer immediately.\n- Write in natural, conversational language — the user may speak \n  your answer aloud.\n- If you are unsure, say so briefly rather than guessing.\n- No bullet points, no markdown headers, no formatting. Plain prose only.\n- Always write from the perspective of the user — "you can", "your \n  store", "in your case".';return e&&e.trim().length>0?`${n}\n\nCurrent meeting context: ${e.trim()}`:n}export function buildUserPrompt(e,n){return`Recent conversation:\n${e.join("\n")}\n\nQuestion to answer:\n${n}\n\nProvide a concise, spoken-language answer the user can give right now.`}